import { readFile, writeFile } from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const here = path.dirname(fileURLToPath(import.meta.url))
const rootDir = path.resolve(here, '..')
const outFile = path.join(here, 'preview-bundle.js')

const sourceFiles = [
  'script/default-options.js',
  'script/img-util.js',
  'script/set-img-attributes.js',
]

const stripEsmSyntax = (source) => {
  return source
    .replace(/^import\s*\{[\s\S]*?\}\s*from\s*['"][^'"]+['"]\s*;?\s*/gm, '')
    .replace(/^\s*export\s*\{[\s\S]*?\}\s*;?\s*$/gm, '')
    .replace(/^export\s+default\s+/gm, 'const __default__ = ')
    .replace(/^export\s+async\s+function\s+/gm, 'async function ')
    .replace(/^export\s+function\s+/gm, 'function ')
    .replace(/^export\s+class\s+/gm, 'class ')
    .replace(/^export\s+const\s+/gm, 'const ')
    .replace(/^export\s+let\s+/gm, 'let ')
    .replace(/^export\s+var\s+/gm, 'var ')
    .trim()
}

const buildBundle = async () => {
  const transformed = []

  for (const relativePath of sourceFiles) {
    const sourcePath = path.join(rootDir, relativePath)
    const source = await readFile(sourcePath, 'utf8')
    transformed.push(stripEsmSyntax(source))
  }

  const bundle = `/* eslint-disable */
/* Generated by example/build-preview-bundle.mjs. */
(function () {
  'use strict'

${transformed.join('\n\n')}

  const target = typeof globalThis !== 'undefined'
    ? globalThis
    : (typeof window !== 'undefined' ? window : this)

  target.RendererImageDom = Object.freeze({
    defaultSharedOptions,
    defaultDomOptions,
    defaultNodeOptions,
    classifyResizeHint,
    createContext,
    applyImageTransforms,
    applyImageTransformsToString,
    startObserver,
    runInPreview,
  })
})()
`

  await writeFile(outFile, bundle, 'utf8')
}

await buildBundle()
